Функция ГруппироватьТаблицу(Таблица, ИмяКолонкиГруппировки, ИмяКолонкиСуммы) Экспорт
	Результат = Новый ТаблицаЗначений;
	Результат.Колонки.Добавить("Группировка");
	Результат.Колонки.Добавить("Сумма");

	Суммы = Новый Соответствие;

	Для каждого Строка Из Таблица Цикл
		Ключ = Строка[ИмяКолонкиГруппировки];
		ЗначениеСуммы = Строка[ИмяКолонкиСуммы];

		Если Суммы.СодержитКлюч(Ключ) Тогда
			Суммы[Ключ] = Суммы[Ключ] + ЗначениеСуммы;
		Иначе
			Суммы.Вставить(Ключ, ЗначениеСуммы);
		КонецЕсли;
	КонецЦикла;

	Для каждого КлючЗначение Из Суммы Цикл
		Стр = Результат.Добавить();
		Стр.Группировка = КлючЗначение.Ключ;
		Стр.Сумма = КлючЗначение.Значение;
	КонецЦикла;

	Возврат Результат;
